elements.content:
flowchart LR
  CODE["JavaScript Code"] --> RT["Runtime<br/>• engine<br/>• built-in APIs<br/>• environment"]
  RT --> B["Browser<br/>Web APIs"]
  RT --> N["Node.js<br/>server APIs"]
  RT --> E["Engine<br/>executes code"]

  classDef active fill:#00E5FF,stroke:#7CFFB2,color:#061018,stroke-width:4px;
  classDef secondary fill:#17213A,stroke:#506080,color:#DCE8FF,stroke-width:2px;
  class CODE,RT,E active;
  class B,N secondary;

flowchart TB
  TOP["Currently Running"] --> BAR["bar()"]
  BAR --> FOO["foo()"]
  FOO --> MAIN["main()"]
  MAIN --> BASE["Call Stack"]

  classDef active fill:#FFD166,stroke:#FF3D81,color:#111827,stroke-width:4px;
  classDef stack fill:#17213A,stroke:#5F6F95,color:#EAF2FF,stroke-width:2px;
  class TOP,BAR active;
  class FOO,MAIN,BASE stack;

flowchart LR
  CODE["JavaScript Code"] --> STACK["Call Stack"]
  STACK --> API["Web APIs<br/>timers, network"]
  API --> TASKQ["Task Queue<br/>callbacks"]
  TASKQ --> LOOP["Event Loop"]
  LOOP --> STACK

  classDef active fill:#00E5FF,stroke:#7CFFB2,color:#061018,stroke-width:4px;
  classDef inactive fill:#17213A,stroke:#506080,color:#DCE8FF,stroke-width:2px;
  class API,TASKQ,LOOP active;
  class CODE,STACK inactive;
  linkStyle 1 stroke:#00E5FF,stroke-width:4px;
  linkStyle 2 stroke:#00E5FF,stroke-width:4px;
  linkStyle 3 stroke:#00E5FF,stroke-width:4px;
  linkStyle 4 stroke:#00E5FF,stroke-width:4px;

console.log('start');
setTimeout(() => console.log('timeout'), 0);
Promise.resolve().then(() => console.log('promise'));
console.log('end');

flowchart LR
  CODE["Main Script<br/>start → end"] --> STACK["Call Stack"]
  STACK --> API["Web APIs<br/>setTimeout"]
  STACK --> MICRO["Microtask Queue<br/>Promise callback"]
  API --> TASKQ["Task Queue<br/>timer callback"]
  MICRO --> LOOP["Event Loop"]
  TASKQ --> LOOP
  LOOP --> STACK

  classDef active fill:#B8FF4D,stroke:#00E5FF,color:#061018,stroke-width:4px;
  classDef warm fill:#FFD166,stroke:#FF3D81,color:#111827,stroke-width:4px;
  classDef inactive fill:#17213A,stroke:#506080,color:#DCE8FF,stroke-width:2px;
  class CODE,STACK active;
  class MICRO,LOOP warm;
  class API,TASKQ inactive;
  linkStyle 0 stroke:#B8FF4D,stroke-width:4px;
  linkStyle 2 stroke:#FFD166,stroke-width:4px;
  linkStyle 4 stroke:#FFD166,stroke-width:4px;
  linkStyle 6 stroke:#B8FF4D,stroke-width:4px;

flowchart LR
  subgraph BR["Browser Runtime"]
    BJS["JavaScript"] --> BAPI["Web APIs"]
    BAPI --> BLOOP["Event Loop"]
  end

  subgraph ND["Node.js Runtime"]
    NJS["JavaScript"] --> LIB["libuv I/O"]
    LIB --> NLOOP["Event Loop"]
  end

  BLOOP --> OUT["Callbacks Resume"]
  NLOOP --> OUT

  classDef active fill:#00E5FF,stroke:#7CFFB2,color:#061018,stroke-width:4px;
  classDef node fill:#FFD166,stroke:#FF3D81,color:#111827,stroke-width:4px;
  classDef inactive fill:#17213A,stroke:#506080,color:#DCE8FF,stroke-width:2px;
  class BAPI,BLOOP active;
  class LIB,NLOOP node;
  class BJS,NJS,OUT inactive;

flowchart LR
  CHEF["Main Thread<br/>one order at a time"] --> HELPERS["Helpers<br/>timers and I/O"]
  HELPERS --> QUEUE["Ready Queue<br/>callbacks"]
  QUEUE --> LOOP["Event Loop"]
  LOOP --> CHEF
  CHEF --> OUT["Output Order<br/>start, end, promise, timeout"]

  classDef active fill:#B8FF4D,stroke:#00E5FF,color:#061018,stroke-width:4px;
  classDef inactive fill:#17213A,stroke:#506080,color:#DCE8FF,stroke-width:2px;
  class CHEF,QUEUE,LOOP active;
  class HELPERS,OUT inactive;
